{
  "name": "AI Predictive Maintenance System",
  "description": "An intelligent industrial dashboard for monitoring machine health, predicting failures using simulated ML, and generating actionable maintenance recommendations with Gemini AI.",
  "requestFramePermissions": []
}

export type MachineStatus = 'healthy' | 'warning' | 'critical';
export type MachineType = 'CNC Mill' | 'Industrial Pump' | 'Turbine Generator' | 'Conveyor Motor';

export interface SensorData {
  temperature: number;
  vibration: number;
  pressure: number;
  rpm: number;
  operatingHours: number;
  timestamp: string;
}

export interface Machine {
  id: string;
  name: string;
  type: MachineType;
  location: string;
  status: MachineStatus;
  failureProbability: number;
  sensorData: SensorData;
  history: SensorData[];
}

export interface MaintenanceRecommendation {
  summary: string;
  rootCause: string;
  urgency: 'low' | 'medium' | 'high' | 'immediate';
  steps: string[];
  partsNeeded: string[];
  googleSearchSources?: { title: string; uri: string }[];
}

export interface PredictionResult {
  probability: number;
  riskLevel: MachineStatus;
  contributingFactors: string[];
}

import { Machine, MachineType, MachineStatus, SensorData, PredictionResult } from '../types';

const MACHINE_TYPES: MachineType[] = ['CNC Mill', 'Industrial Pump', 'Turbine Generator', 'Conveyor Motor'];
const LOCATIONS = ['Assembly Floor A', 'Production Line 2', 'Power House Sector 4', 'Storage Yard B'];

const generateInitialHistory = (type: MachineType): SensorData[] => {
  const history: SensorData[] = [];
  const baseTemp = type === 'CNC Mill' ? 65 : type === 'Turbine Generator' ? 85 : 55;

  for (let i = 20; i >= 0; i--) {
    const time = new Date(Date.now() - i * 60000).toISOString();
    history.push({
      temperature: baseTemp + Math.random() * 10 - 5,
      vibration: 0.1 + Math.random() * 0.4,
      pressure: 90 + Math.random() * 30,
      rpm: 1500 + Math.random() * 200,
      operatingHours: 1200 - i,
      timestamp: time
    });
  }
  return history;
};

export const INITIAL_MACHINES: Machine[] = [
  {
    id: 'MCH-001',
    name: 'Precision Mill X1',
    type: 'CNC Mill',
    location: 'Assembly Floor A',
    status: 'healthy',
    failureProbability: 12,
    sensorData: generateInitialHistory('CNC Mill')[20],
    history: generateInitialHistory('CNC Mill')
  },
  {
    id: 'MCH-002',
    name: 'High-Pressure Pump P2',
    type: 'Industrial Pump',
    location: 'Production Line 2',
    status: 'warning',
    failureProbability: 45,
    sensorData: generateInitialHistory('Industrial Pump')[20],
    history: generateInitialHistory('Industrial Pump')
  },
  {
    id: 'MCH-003',
    name: 'Main Gen Turbine T4',
    type: 'Turbine Generator',
    location: 'Power House Sector 4',
    status: 'critical',
    failureProbability: 88,
    sensorData: generateInitialHistory('Turbine Generator')[20],
    history: generateInitialHistory('Turbine Generator')
  }
];

// Simple deterministic ML prediction logic for demo
export const predictFailure = (data: SensorData, type: MachineType): PredictionResult => {
  let score = 0;
  const factors: string[] = [];

  // Rules based on industry standards
  if (data.temperature > 85) {
    score += 35;
    factors.push('High Temperature Threshold Exceeded');
  }
  if (data.vibration > 0.8) {
    score += 40;
    factors.push('Excessive Vibration Detected');
  }
  if (data.pressure > 140) {
    score += 25;
    factors.push('Abnormal Pressure Variance');
  }
  if (data.rpm < 1200) {
    score += 15;
    factors.push('RPM Underperformance');
  }

  // Cap at 100
  const probability = Math.min(score, 99);
  let riskLevel: MachineStatus = 'healthy';
  if (probability > 75) riskLevel = 'critical';
  else if (probability > 30) riskLevel = 'warning';

  return { probability, riskLevel, contributingFactors: factors };
};

export const getNextDataPoint = (current: SensorData, type: MachineType): SensorData => {
  // Simulate drift or random fluctuations
  const drift = type === 'Turbine Generator' ? 1.5 : 0.5;
  return {
    temperature: Math.max(20, current.temperature + (Math.random() * 4 - 1.8)),
    vibration: Math.max(0.01, current.vibration + (Math.random() * 0.1 - 0.045)),
    pressure: Math.max(10, current.pressure + (Math.random() * 5 - 2.5)),
    rpm: current.rpm + (Math.random() * 20 - 10),
    operatingHours: current.operatingHours + 0.01,
    timestamp: new Date().toISOString()
  };
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Machine, SensorData, MaintenanceRecommendation } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const getMaintenanceAnalysis = async (machine: Machine): Promise<MaintenanceRecommendation> => {
  const ai = getAIClient();
  const prompt = `Analyze this industrial machine data and provide maintenance recommendations.
  Machine: ${machine.name} (${machine.type})
  Failure Risk: ${machine.failureProbability}%
  Recent Sensors:
  - Temperature: ${machine.sensorData.temperature.toFixed(1)}°C
  - Vibration: ${machine.sensorData.vibration.toFixed(2)} mm/s
  - Pressure: ${machine.sensorData.pressure.toFixed(1)} PSI
  - RPM: ${machine.sensorData.rpm.toFixed(0)}

  Provide a JSON response with: summary, rootCause, urgency (low/medium/high/immediate), steps (array), partsNeeded (array).`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            rootCause: { type: Type.STRING },
            urgency: { type: Type.STRING },
            steps: { type: Type.ARRAY, items: { type: Type.STRING } },
            partsNeeded: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["summary", "rootCause", "urgency", "steps", "partsNeeded"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data as MaintenanceRecommendation;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return {
      summary: "AI analysis unavailable. Manual inspection recommended.",
      rootCause: "Data threshold exceedance detected.",
      urgency: machine.failureProbability > 80 ? 'immediate' : 'medium',
      steps: ["Perform physical check", "Review sensor logs", "Notify supervisor"],
      partsNeeded: ["None identified"]
    };
  }
};

export const getDeepDiagnostic = async (machine: Machine): Promise<string> => {
  const ai = getAIClient();
  const prompt = `Perform a deep diagnostic thinking analysis on why machine ${machine.name} (${machine.type}) is showing a ${machine.failureProbability}% failure probability. Consider physics of the machine, environmental factors, and historical sensor drift.

  Recent Stats: Temp ${machine.sensorData.temperature.toFixed(1)}C, Vibration ${machine.sensorData.vibration.toFixed(2)}mm/s.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });
    return response.text || "No diagnostic results.";
  } catch (error) {
    return "Deep diagnostic error: " + (error as Error).message;
  }
};

export const searchIndustryBestPractices = async (machineType: string): Promise<any> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `What are the latest preventive maintenance best practices for a ${machineType} in 2024? Search for industrial safety standards and official manufacturer guidelines.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web).filter(Boolean) || []
  };
};

