          <Bell className="w-5 h-5 text-indigo-400" />
          <h2 className="text-lg font-bold text-white">System Alerts</h2>
          {unreadCount > 0 && (
            <span className="bg-rose-500 text-white text-[10px] font-black px-1.5 py-0.5 rounded-full">
              {unreadCount}
            </span>
          )}
        </div>
        <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3">
        {alerts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-2">
            <Bell className="w-8 h-8 opacity-20" />
            <p className="text-sm">No active alerts</p>
          </div>
        ) : (
          alerts.map(alert => (
            <div 
              key={alert.id} 
              className={`p-4 rounded-xl border transition-all ${alert.read ? 'bg-slate-900/50 border-slate-800' : 'bg-slate-800 border-indigo-500/30 shadow-lg shadow-indigo-500/5'}`}
              onClick={() => onMarkRead(alert.id)}
            >
              <div className="flex items-start gap-3">
                <div className="mt-0.5">{getSeverityIcon(alert.severity)}</div>
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start">
                    <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{alert.machineName}</span>
                    <span className="text-[10px] text-slate-500">{new Date(alert.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <p className="text-sm text-slate-200 font-medium mt-1 leading-snug">{alert.message}</p>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {alerts.length > 0 && (
        <div className="p-4 border-t border-slate-800">
          <button 
            onClick={onClearAll}
            className="w-full py-2 text-xs font-bold text-slate-400 hover:text-white transition-colors"
          >
            Clear All Notifications
          </button>
        </div>
      )}
    </div>
  );
};

