const App = () => {
  const [machines, setMachines] = useState<Machine[]>(INITIAL_MACHINES);
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [isAlertsOpen, setIsAlertsOpen] = useState(false);
  const dataIntervalRef = useRef<number | null>(null);

  const addAlert = useCallback((machine: Machine, message: string, severity: 'low' | 'medium' | 'high' = 'medium') => {
    const newAlert: Alert = {
      id: Math.random().toString(36).substr(2, 9),
      machineId: machine.id,
      machineName: machine.name,
      type: 'threshold_exceeded',
      severity,
      message,
      timestamp: new Date().toISOString(),
      read: false
    };
    setAlerts(prev => [newAlert, ...prev].slice(0, 50));
  }, []);

  useEffect(() => {
    // Start simulation loop
    dataIntervalRef.current = window.setInterval(() => {
      setMachines(prev => prev.map(m => {
        const nextData = getNextDataPoint(m.sensorData, m.type);
        const history = [...m.history.slice(-19), nextData];
        const { probability, riskLevel } = predictFailure(nextData, m.type);

        // Alert logic: if status transitioned to warning/critical
        if (m.status !== riskLevel && riskLevel !== 'healthy') {
          addAlert(
            m, 
            `Status changed to ${riskLevel.toUpperCase()}. Probability of failure reached ${probability}%.`,
            riskLevel === 'critical' ? 'high' : 'medium'
          );
        }

        // Specific threshold alerts
        if (nextData.temperature > 90 && m.sensorData.temperature <= 90) {
          addAlert(m, `Temperature spike detected: ${nextData.temperature.toFixed(1)}°C`, 'high');
        }

        return {
          ...m,
          sensorData: nextData,
          history,
          failureProbability: probability,
          status: riskLevel
        };
      }));
    }, 5000);

    return () => {
      if (dataIntervalRef.current) clearInterval(dataIntervalRef.current);
    };
  }, [addAlert]);

  const unreadCount = alerts.filter(a => !a.read).length;

  return (
    <HashRouter>
      <div className="flex min-h-screen bg-slate-950 text-slate-100 overflow-hidden relative">
        <Sidebar unreadAlerts={unreadCount} onToggleAlerts={() => setIsAlertsOpen(!isAlertsOpen)} />

        <main className="flex-1 h-screen overflow-y-auto bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-slate-950">
          <Routes>
            <Route path="/" element={<Dashboard machines={machines} alerts={alerts} />} />
            <Route path="/machine/:id" element={<MachineDetails machines={machines} />} />
          </Routes>
        </main>

        <NotificationCenter 
          alerts={alerts}
          isOpen={isAlertsOpen}
          onClose={() => setIsAlertsOpen(false)}
          onMarkRead={(id) => setAlerts(prev => prev.map(a => a.id === id ? { ...a, read: true } : a))}
          onClearAll={() => setAlerts([])}
        />
      </div>
    </HashRouter>
  );
};

export default App;

