// --- Auth Context ---

interface AuthContextType {
  isAuthenticated: boolean;
  role: UserRole | null;
  user: string | null;
  login: (u: string, p: string) => boolean;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | null>(null);

const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => localStorage.getItem('prefix_ai_auth') === 'true');
  const [role, setRole] = useState<UserRole | null>(() => localStorage.getItem('prefix_ai_role') as UserRole || null);
  const [user, setUser] = useState<string | null>(() => localStorage.getItem('prefix_ai_user') || null);

  const login = (u: string, p: string) => {
    if (u === 'admin' && p === 'admin') {
      setIsAuthenticated(true);
      setRole('admin');
      setUser('Plant Manager');
      localStorage.setItem('prefix_ai_auth', 'true');
      localStorage.setItem('prefix_ai_role', 'admin');
      localStorage.setItem('prefix_ai_user', 'Plant Manager');
      return true;
    } else if (u === 'user' && p === 'user') {
      setIsAuthenticated(true);
      setRole('engineer');
      setUser('Site Engineer');
      localStorage.setItem('prefix_ai_auth', 'true');
      localStorage.setItem('prefix_ai_role', 'engineer');
      localStorage.setItem('prefix_ai_user', 'Site Engineer');
      return true;
    }
    return false;
  };

  const logout = () => {
    setIsAuthenticated(false);
    setRole(null);
    setUser(null);
    localStorage.clear();
  };

  return (
    <AuthContext.Provider value={{ isAuthenticated, role, user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const ProtectedRoute: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated } = useAuth();
  const location = useLocation();
  if (!isAuthenticated) return <Navigate to="/login" state={{ from: location }} replace />;
  return <>{children}</>;
};

