const App = () => {
  // Use INITIAL_MACHINES directly as they now contain all required properties
  const [machines, setMachines] = useState<Machine[]>(INITIAL_MACHINES);
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [isAlertsOpen, setIsAlertsOpen] = useState(false);
  const [report, setReport] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  // Fix: Explicitly type the new alert object to avoid string type mismatch errors
  const addAlert = useCallback((m: Machine, msg: string, sev: 'low'|'medium'|'high' = 'medium') => {
    setAlerts(p => {
      const newAlert: Alert = {
        id: Math.random().toString(36).substr(2,9), 
        machineId: m.id, 
        machineName: m.name, 
        type: 'threshold_exceeded', 
        severity: sev, 
        message: msg, 
        timestamp: new Date().toISOString(), 
        read: false
      };
      return [newAlert, ...p].slice(0, 50);
    });
  }, []);

  const addLog = (mid: string, action: string, notes: string) => {
    setMachines(prev => prev.map(m => m.id === mid ? {...m, logs: [{id: Date.now().toString(), timestamp: new Date().toISOString(), operator: localStorage.getItem('prefix_ai_user') || 'System', action, notes}, ...m.logs]} : m));
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const res = await generateFleetReport(machines);
    setReport(res);
    setIsGenerating(false);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setMachines(prev => prev.map(m => {
        const next = getNextDataPoint(m.sensorData, m.type);
        const { probability, riskLevel } = predictFailure(next, m.type);
        if (m.status !== riskLevel && riskLevel !== 'healthy') addAlert(m, `Hazard Warning: Risk at ${probability}%`, riskLevel === 'critical' ? 'high' : 'medium');
        return {...m, sensorData: next, history: [...m.history.slice(-19), next], failureProbability: probability, status: riskLevel};
      }));
    }, 5000);
    return () => clearInterval(timer);
  }, [addAlert]);

  return (
    <AuthProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/*" element={
            <ProtectedRoute>
              <div className="flex h-screen bg-slate-950 overflow-hidden">
                <Sidebar unreadCount={alerts.filter(a => !a.read).length} onToggleAlerts={() => setIsAlertsOpen(!isAlertsOpen)} />
                <main className="flex-1 overflow-y-auto bg-slate-950">
                  <Routes>
                    <Route path="/" element={<Dashboard machines={machines} onGenerateReport={handleGenerateReport} />} />
                    <Route path="/machine/:id" element={<MachineDetails machines={machines} onAddLog={addLog} />} />
                  </Routes>
                </main>
                <NotificationCenter alerts={alerts} isOpen={isAlertsOpen} onClose={() => setIsAlertsOpen(false)} onMarkRead={id => setAlerts(p => p.map(a => a.id === id ? {...a, read: true} : a))} onClearAll={() => setAlerts([])} />
                {isGenerating && <div className="fixed inset-0 z-[70] bg-black/60 backdrop-blur-md flex items-center justify-center flex-col gap-4">
                  <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
                  <p className="text-white font-black tracking-widest uppercase">Synthesizing Report...</p>
                </div>}
                {report && <ReportModal content={report} onClose={() => setReport(null)} />}
              </div>
            </ProtectedRoute>
          } />
        </Routes>
      </HashRouter>
    </AuthProvider>
  );
};

export default App;

