    setChatHistory(prev => [...prev, {role: 'u', text: msg}]);
    setIsTyping(true);
    const reply = await askMachineChat(msg, machine);
    setIsTyping(false);
    setChatHistory(prev => [...prev, {role: 'ai', text: reply}]);
