const App = () => {
  const [machines, setMachines] = useState<Machine[]>(INITIAL_MACHINES);
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [isAlertsOpen, setIsAlertsOpen] = useState(false);
  const [report, setReport] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [registeredPhone, setRegisteredPhone] = useState<string>(() => localStorage.getItem('prefix_ai_phone') || '');
  const [smsNotification, setSmsNotification] = useState<{msg: string, to: string} | null>(null);
  const extremeAlertsRef = useRef<Set<string>>(new Set());

  const getRecommendationMessage = (machine: Machine, prob: number) => {
    if (prob > 85) {
      switch (machine.type) {
        case 'CNC Mill': return `EMERGENCY: Failure probability ${prob}%. Spindle vibration critical. Recommendation: Immediate stop mill and inspect coolant pump.`;
        case 'Industrial Pump': return `EMERGENCY: Failure probability ${prob}%. Cavitation levels extreme. Recommendation: Shutdown pump P-sector immediately.`;
        case 'Turbine Generator': return `EMERGENCY: Failure probability ${prob}%. Main bearing heat at peak. Recommendation: Safe-state shutdown; inspect lube pressure.`;
        case 'Conveyor Motor': return `EMERGENCY: Failure probability ${prob}%. Stator current overflow. Recommendation: Emergency stop; inspect motor windings.`;
        default: return `EMERGENCY: Immediate shutdown and engineering inspection required for ${machine.name}. Risk at ${prob}%.`;
      }
    }
    return `Hazard Detection: Asset enters ${machine.status.toUpperCase()} state. Prob: ${prob}%`;
  };

  const addAlert = useCallback((m: Machine, msg: string, sev: 'low'|'medium'|'high' = 'medium') => {
    setAlerts(p => {
      const newAlert: Alert = {
        id: Math.random().toString(36).substr(2,9), 
        machineId: m.id, 
        machineName: m.name, 
        type: 'threshold_exceeded', 
        severity: sev, 
        message: msg, 
        timestamp: new Date().toISOString(), 
        read: false
      };

      if (sev === 'high' && registeredPhone) {
        setSmsNotification({ msg, to: registeredPhone });
        setTimeout(() => setSmsNotification(null), 6000);
      }

      return [newAlert, ...p].slice(0, 50);
    });
  }, [registeredPhone]);

  const addLog = (mid: string, action: string, notes: string) => {
    setMachines(prev => prev.map(m => m.id === mid ? {...m, logs: [{id: Date.now().toString(), timestamp: new Date().toISOString(), operator: localStorage.getItem('prefix_ai_user') || 'System', action, notes}, ...m.logs]} : m));
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const res = await generateFleetReport(machines);
    setReport(res);
    setIsGenerating(false);
  };

  const handleRegisterPhone = (phone: string) => {
    setRegisteredPhone(phone);
    localStorage.setItem('prefix_ai_phone', phone);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setMachines(prev => prev.map(m => {
        const next = getNextDataPoint(m.sensorData, m.type);
        const { probability, riskLevel } = predictFailure(next, m.type);

        // Handle transitions to warning/critical
        if (m.status !== riskLevel && riskLevel !== 'healthy') {
          const msg = getRecommendationMessage(m, probability);
          addAlert(m, msg, probability > 85 ? 'high' : 'medium');
        } 
        // Handle extreme risk crossing (>85%) even if already critical
        else if (probability > 85 && !extremeAlertsRef.current.has(m.id)) {
          extremeAlertsRef.current.add(m.id);
          const msg = getRecommendationMessage(m, probability);
          addAlert(m, msg, 'high');
        } 
        // Reset extreme risk flag if it drops below threshold
        else if (probability < 80 && extremeAlertsRef.current.has(m.id)) {
          extremeAlertsRef.current.delete(m.id);
        }

        return {...m, sensorData: next, history: [...m.history.slice(-19), next], failureProbability: probability, status: riskLevel};
      }));
    }, 5000);
    return () => clearInterval(timer);
  }, [addAlert]);

  return (
    <AuthProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/*" element={
            <ProtectedRoute>
              <div className="flex h-screen bg-slate-950 overflow-hidden relative">
                <Sidebar unreadCount={alerts.filter(a => !a.read).length} onToggleAlerts={() => setIsAlertsOpen(!isAlertsOpen)} />
                <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
                  <SmsNotificationBar phoneNumber={registeredPhone} onRegister={handleRegisterPhone} />
                  <div className="flex-1 overflow-y-auto">
                    <Routes>
                      <Route path="/" element={<Dashboard machines={machines} onGenerateReport={handleGenerateReport} />} />
                      <Route path="/machine/:id" element={<MachineDetails machines={machines} onAddLog={addLog} />} />
                    </Routes>
                  </div>
                </main>
                <NotificationCenter alerts={alerts} isOpen={isAlertsOpen} onClose={() => setIsAlertsOpen(false)} onMarkRead={id => setAlerts(p => p.map(a => a.id === id ? {...a, read: true} : a))} onClearAll={() => setAlerts([])} />

                {/* Simulated SMS Toast */}
                {smsNotification && (
                  <div className="fixed bottom-10 right-10 z-[100] bg-white text-slate-900 p-5 rounded-[2rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.5)] border-l-8 border-indigo-600 flex items-start gap-5 animate-in slide-in-from-right duration-500 max-w-sm">
                    <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center shrink-0">
