const App = () => {
  const [machines, setMachines] = useState<Machine[]>(INITIAL_MACHINES);
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [isAlertsOpen, setIsAlertsOpen] = useState(false);
  const [report, setReport] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [registeredPhone, setRegisteredPhone] = useState<string>(() => localStorage.getItem('prefix_ai_phone') || '');
  const [smsNotification, setSmsNotification] = useState<{msg: string, to: string} | null>(null);
  const extremeAlertsRef = useRef<Set<string>>(new Set());

  const getRecommendationMessage = (machine: Machine, prob: number) => {
    if (prob > 85) {
      switch (machine.type) {
        case 'CNC Mill': return `EMERGENCY: Failure probability ${prob}%. Spindle vibration critical. Recommendation: Immediate stop mill and inspect coolant pump.`;
        case 'Industrial Pump': return `EMERGENCY: Failure probability ${prob}%. Cavitation levels extreme. Recommendation: Shutdown pump P-sector immediately.`;
        case 'Turbine Generator': return `EMERGENCY: Failure probability ${prob}%. Main bearing heat at peak. Recommendation: Safe-state shutdown; inspect lube pressure.`;
        case 'Conveyor Motor': return `EMERGENCY: Failure probability ${prob}%. Stator current overflow. Recommendation: Emergency stop; inspect motor windings.`;
        default: return `EMERGENCY: Immediate shutdown and engineering inspection required for ${machine.name}. Risk at ${prob}%.`;
      }
    }
    return `Hazard Detection: Asset enters ${machine.status.toUpperCase()} state. Prob: ${prob}%`;
  };

  const addAlert = useCallback((m: Machine, msg: string, sev: 'low'|'medium'|'high' = 'medium') => {
    setAlerts(p => {
      const newAlert: Alert = {
        id: Math.random().toString(36).substr(2,9), 
        machineId: m.id, 
        machineName: m.name, 
        type: 'threshold_exceeded', 
        severity: sev, 
        message: msg, 
        timestamp: new Date().toISOString(), 
        read: false
      };

      if (sev === 'high' && registeredPhone) {
        setSmsNotification({ msg, to: registeredPhone });
        setTimeout(() => setSmsNotification(null), 6000);
      }

      return [newAlert, ...p].slice(0, 50);
    });
  }, [registeredPhone]);

  const addLog = (mid: string, action: string, notes: string) => {
    setMachines(prev => prev.map(m => m.id === mid ? {...m, logs: [{id: Date.now().toString(), timestamp: new Date().toISOString(), operator: localStorage.getItem('prefix_ai_user') || 'System', action, notes}, ...m.logs]} : m));
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const res = await generateFleetReport(machines);
    setReport(res);
    setIsGenerating(false);
  };

  const handleRegisterPhone = (phone: string) => {
    setRegisteredPhone(phone);
    localStorage.setItem('prefix_ai_phone', phone);
  };

  useEffect(() => {
    const timer = setInterval(() => {
      setMachines(prev => {
        const updated = prev.map(m => {
          const next = getNextDataPoint(m.sensorData, m.type);
          const { probability, riskLevel } = predictFailure(next, m.type);

          // Handle transitions to warning/critical
          const triggerAlert = async () => {
             if (m.status !== riskLevel && riskLevel !== 'healthy') {
                if (probability > 85 && !extremeAlertsRef.current.has(m.id)) {
                  extremeAlertsRef.current.add(m.id);
                  // ASYNC AI RECOMMENDATION FOR CRITICAL ALERTS
                  try {
                    const aiRec = await getMaintenanceAnalysis({ ...m, failureProbability: probability, sensorData: next });
                    const detailedMsg = `CRITICAL ALERT: ${aiRec.summary}\n\nROOT CAUSE: ${aiRec.rootCause}\n\nURGENT ACTIONS:\n${aiRec.steps.map((s, i) => `${i+1}. ${s}`).join('\n')}`;
                    addAlert(m, detailedMsg, 'high');
                  } catch (e) {
                    const fallbackMsg = getRecommendationMessage(m, probability);
                    addAlert(m, fallbackMsg, 'high');
                  }
                } else if (probability <= 85) {
                   const msg = getRecommendationMessage(m, probability);
                   addAlert(m, msg, 'medium');
                }
              } 
              // Reset extreme risk flag if it drops below threshold
              else if (probability < 80 && extremeAlertsRef.current.has(m.id)) {
                extremeAlertsRef.current.delete(m.id);
              }
          };

          triggerAlert();

          return {...m, sensorData: next, history: [...m.history.slice(-19), next], failureProbability: probability, status: riskLevel};
        });
        return updated;
      });
    }, 5000);
    return () => clearInterval(timer);
  }, [addAlert]);

  return (
    <AuthProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/*" element={
            <ProtectedRoute>
              <div className="flex h-screen bg-slate-950 overflow-hidden relative">
                <Sidebar unreadCount={alerts.filter(a => !a.read).length} onToggleAlerts={() => setIsAlertsOpen(!isAlertsOpen)} />
                <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
                  <SmsNotificationBar phoneNumber={registeredPhone} onRegister={handleRegisterPhone} />
                  <div className="flex-1 overflow-y-auto">
                    <Routes>
                      <Route path="/" element={<Dashboard machines={machines} onGenerateReport={handleGenerateReport} />} />
                      <Route path="/machine/:id" element={<MachineDetails machines={machines} onAddLog={addLog} />} />
                    </Routes>
                  </div>
                </main>
                <NotificationCenter alerts={alerts} isOpen={isAlertsOpen} onClose={() => setIsAlertsOpen(false)} onMarkRead={id => setAlerts(p => p.map(a => a.id === id ? {...a, read: true} : a))} onClearAll={() => setAlerts([])} />

                {/* Simulated SMS Toast */}
                {smsNotification && (
                  <div className="fixed bottom-10 right-10 z-[100] bg-white text-slate-900 p-5 rounded-[2rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.5)] border-l-8 border-indigo-600 flex items-start gap-5 animate-in slide-in-from-right duration-500 max-w-sm">
                    <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center shrink-0">
                      <Smartphone className="w-6 h-6 text-indigo-600" />
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Mobile Alert Sent</span>
                        <span className="text-[10px] text-slate-400 font-mono">NOW</span>
                      </div>
                      <p className="text-xs font-black mb-1 italic">Message to {smsNotification.to}</p>
                      <p className="text-xs text-slate-600 leading-snug font-medium line-clamp-4">{smsNotification.msg}</p>
                    </div>
                  </div>
                )}

                {isGenerating && (
                  <div className="fixed inset-0 z-[70] bg-black/80 backdrop-blur-xl flex items-center justify-center flex-col gap-6">
                    <div className="relative">
                      <Loader2 className="w-16 h-16 text-indigo-500 animate-spin" />
                      <BrainCircuit className="absolute inset-0 m-auto w-6 h-6 text-white animate-pulse" />
                    </div>
                    <p className="text-white font-black tracking-[0.4em] uppercase text-xs">Synthesizing Intelligence Report</p>
                  </div>
                )}
                {report && <ReportModal content={report} onClose={() => setReport(null)} />}
              </div>
            </ProtectedRoute>
          } />
        </Routes>
      </HashRouter>
    </AuthProvider>
  );
};

export default App;

import React from 'react';
import { Alert } from '../types';
import { Bell, X, AlertTriangle, Info, ShieldAlert } from 'lucide-react';

interface NotificationCenterProps {
  alerts: Alert[];
  onMarkRead: (id: string) => void;
  onClearAll: () => void;
  isOpen: boolean;
  onClose: () => void;
}

export const NotificationCenter: React.FC<NotificationCenterProps> = ({ 
  alerts, onMarkRead, onClearAll, isOpen, onClose 
}) => {
  if (!isOpen) return null;

  const unreadCount = alerts.filter(a => !a.read).length;

  const getSeverityIcon = (severity: string) => {
    switch (severity) {
      case 'high': return <ShieldAlert className="w-5 h-5 text-rose-500" />;
      case 'medium': return <AlertTriangle className="w-5 h-5 text-amber-500" />;
      default: return <Info className="w-5 h-5 text-blue-500" />;
    }
  };

  return (
    <div className="fixed top-0 right-0 h-screen w-80 lg:w-96 bg-slate-900 border-l border-slate-800 z-50 shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
      <div className="p-6 border-b border-slate-800 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Bell className="w-5 h-5 text-indigo-400" />
          <h2 className="text-lg font-bold text-white uppercase italic tracking-tighter">System Alerts</h2>
          {unreadCount > 0 && (
            <span className="bg-rose-500 text-white text-[10px] font-black px-1.5 py-0.5 rounded-full ring-4 ring-slate-900">
              {unreadCount}
            </span>
          )}
        </div>
        <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
        {alerts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-2 opacity-30 italic">
            <Bell className="w-8 h-8" />
            <p className="text-[10px] font-black uppercase tracking-widest">No active incidents</p>
          </div>
        ) : (
          alerts.map(alert => (
            <div 
              key={alert.id} 
              className={`p-4 rounded-2xl border transition-all cursor-pointer ${
                alert.read 
                  ? 'bg-slate-900/50 border-slate-800 opacity-60' 
                  : alert.severity === 'high' 
                    ? 'bg-rose-500/10 border-rose-500/30 shadow-[0_0_20px_rgba(244,63,94,0.1)]' 
                    : 'bg-slate-800 border-indigo-500/30 shadow-lg'
              }`}
              onClick={() => onMarkRead(alert.id)}
            >
              <div className="flex items-start gap-3">
                <div className="mt-0.5 shrink-0">{getSeverityIcon(alert.severity)}</div>
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest truncate max-w-[150px]">
                      {alert.machineName}
                    </span>
                    <span className="text-[9px] font-mono text-slate-500">
                      {new Date(alert.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                  </div>
                  <div className="text-xs text-slate-200 leading-relaxed whitespace-pre-wrap">
                    {alert.message}
                  </div>
                  {!alert.read && (
                    <div className="mt-3 text-[8px] font-black text-indigo-400 uppercase tracking-[0.2em] animate-pulse">
                      Pending Action
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {alerts.length > 0 && (
        <div className="p-4 border-t border-slate-800 bg-slate-950/50">
          <button 
            onClick={onClearAll}
            className="w-full py-3 text-[10px] font-black text-slate-500 hover:text-rose-400 transition-colors uppercase tracking-[0.2em]"
          >
            Purge Incident Archive
          </button>
        </div>
      )}
    </div>
  );
};

